@app.route("/users", methods=["POST"])
def create_user():
    payload, err = require_json()
    if err:
        return err

    username = (payload.get("username") or "").strip()
    email = (payload.get("email") or "").strip() or None
    display_name = (payload.get("display_name") or "").strip() or username
    bio = (payload.get("bio") or "").strip()
    roles = payload.get("roles") or ["user"]
    metadata = payload.get("metadata") or {}

    if not username:
        return jsonify({"error": "username is required"}), 400

    doc = {
        "username": username,
        "email": email,
        "display_name": display_name,
        "bio": bio,
        "roles": roles if isinstance(roles, list) else ["user"],
        "metadata": metadata if isinstance(metadata, dict) else {},
        "created_at": now_utc(),
        "updated_at": now_utc(),
    }

    try:
        res = users.insert_one(doc)
    except DuplicateKeyError:
        return jsonify({"error": "username or email already exists"}), 409

    created = users.find_one({"_id": res.inserted_id})
    return jsonify(json_oid(created)), 201


