@app.route("/documents", methods=["GET"])
def list_documents():
    q = (request.args.get("q") or "").strip()
    status = (request.args.get("status") or "").strip()
    tag = (request.args.get("tag") or "").strip()
    author_id = (request.args.get("author_id") or "").strip()
    sort = (request.args.get("sort") or "updated_at").strip()
    order = (request.args.get("order") or "desc").strip().lower()
    limit = parse_int(request.args.get("limit", 20), default=20, min_value=1, max_value=200)
    skip = parse_int(request.args.get("skip", 0), default=0, min_value=0)

    filt = {}
    if status:
        filt["status"] = status
    if tag:
        filt["tags"] = tag
    if author_id:
        try:
            filt["author_id"] = oid(author_id, "author_id")
        except ValueError as e:
            return jsonify({"error": str(e)}), 400

    if q:
        filt["$text"] = {"$search": q}

    sort_field = sort if sort in {"created_at", "updated_at", "title", "status"} else "updated_at"
    direction = DESCENDING if order != "asc" else ASCENDING

    projection = {"score": {"$meta": "textScore"}} if q else None
    cursor = documents.find(filt, projection=projection)
    if q:
        cursor = cursor.sort([("score", {"$meta": "textScore"}), (sort_field, direction)])
    else:
        cursor = cursor.sort(sort_field, direction)

    total = documents.count_documents(filt)
    items = [json_oid(d) for d in cursor.skip(skip).limit(limit)]
    return jsonify({"total": total, "count": len(items), "items": items}), 200


