@app.route("/analytics/documents/by_status", methods=["GET"])
def analytics_by_status():
    pipeline = [
        {"$group": {"_id": "$status", "count": {"$sum": 1}}},
        {"$project": {"_id": 0, "status": "$_id", "count": 1}},
        {"$sort": {"count": -1, "status": 1}},
    ]
    results = list(documents.aggregate(pipeline))
    return jsonify({"items": results}), 200


@app.route("/analytics/documents/by_tag", methods=["GET"])
def analytics_by_tag():
    limit = parse_int(request.args.get("limit", 20), default=20, min_value=1, max_value=200)
    status = (request.args.get("status") or "").strip()

    match = {}
    if status:
        match["status"] = status

    pipeline = []
    if match:
        pipeline.append({"$match": match})

    pipeline += [
        {"$unwind": "$tags"},
        {"$group": {"_id": "$tags", "count": {"$sum": 1}}},
        {"$project": {"_id": 0, "tag": "$_id", "count": 1}},
        {"$sort": {"count": -1, "tag": 1}},
        {"$limit": limit},
    ]
    results = list(documents.aggregate(pipeline))
    return jsonify({"items": results}), 200


@app.route("/analytics/authors/top", methods=["GET"])
def analytics_top_authors():
    limit = parse_int(request.args.get("limit", 10), default=10, min_value=1, max_value=100)
    status = (request.args.get("status") or "").strip()

    match = {}
    if status:
        match["status"] = status

    pipeline = []
    if match:
        pipeline.append({"$match": match})

    pipeline += [
        {"$group": {"_id": "$author_id", "documents": {"$sum": 1}, "last_updated": {"$max": "$updated_at"}}},
        {"$sort": {"documents": -1, "last_updated": -1}},
        {"$limit": limit},
        {"$lookup": {"from": "users", "localField": "_id", "foreignField": "_id", "as": "author"}},
        {"$unwind": {"path": "$author", "preserveNullAndEmptyArrays": True}},
        {"$project": {"_id": 0, "author_id": {"$toString": "$_id"}, "documents": 1, "last_updated": 1,
                      "author": {"_id": {"$toString": "$author._id"}, "username": "$author.username",
                                 "display_name": "$author.display_name", "email": "$author.email"}}},
    ]
    results = list(documents.aggregate(pipeline))
    for r in results:
        if isinstance(r.get("last_updated"), datetime):
            r["last_updated"] = r["last_updated"].isoformat() + "Z"
        if isinstance(r.get("author"), dict):
            if r["author"].get("_id") is None:
                r["author"] = None
    return jsonify({"items": results}), 200


@app.route("/analytics/documents/timeline", methods=["GET"])
def analytics_documents_timeline():
    period = (request.args.get("period") or "day").strip().lower()
    status = (request.args.get("status") or "").strip()

    if period not in {"day", "month"}:
        return jsonify({"error": "period must be 'day' or 'month'"}), 400

    match = {}
    if status:
        match["status"] = status

    date_expr = {
        "$dateToString": {
            "format": "%Y-%m-%d" if period == "day" else "%Y-%m",
            "date": "$created_at",
        }
    }

    pipeline = []
    if match:
        pipeline.append({"$match": match})

    pipeline += [
        {"$group": {"_id": date_expr, "count": {"$sum": 1}}},
        {"$project": {"_id": 0, "bucket": "$_id", "count": 1}},
        {"$sort": {"bucket": 1}},
    ]

    results = list(documents.aggregate(pipeline))
    return jsonify({"items": results}), 200


@app.route("/search/advanced", methods=["POST"])
def advanced_search():
    payload, err = require_json()
    if err:
        return err

    q = (payload.get("q") or "").strip()
    status = (payload.get("status") or "").strip()
    tags = payload.get("tags") or []
    author_id = (payload.get("author_id") or "").strip()
    created_from = payload.get("created_from")
    created_to = payload.get("created_to")
    limit = parse_int(payload.get("limit", 20), default=20, min_value=1, max_value=200)
    skip = parse_int(payload.get("skip", 0), default=0, min_value=0)

    match = {}
    if status:
        match["status"] = status
    if tags:
        if not isinstance(tags, list):
            return jsonify({"error": "tags must be a list"}), 400
        match["tags"] = {"$all": tags}
    if author_id:
        try:
            match["author_id"] = oid(author_id, "author_id")
        except ValueError as e:
            return jsonify({"error": str(e)}), 400
    if created_from or created_to:
        rng = {}
        if created_from:
            try:
                rng["$gte"] = datetime.fromisoformat(created_from.replace("Z", "+00:00")).replace(tzinfo=None)
            except Exception:
                return jsonify({"error": "created_from must be ISO date/time"}), 400
        if created_to:
            try:
                rng["$lte"] = datetime.fromisoformat(created_to.replace("Z", "+00:00")).replace(tzinfo=None)
            except Exception:
                return jsonify({"error": "created_to must be ISO date/time"}), 400
        match["created_at"] = rng
    if q:
        match["$text"] = {"$search": q}

    pipeline = [{"$match": match}]
    if q:
        pipeline.append({"$addFields": {"score": {"$meta": "textScore"}}})
        pipeline.append({"$sort": {"score": -1, "updated_at": -1}})
    else:
        pipeline.append({"$sort": {"updated_at": -1}})
    pipeline.append({"$facet": {"items": [{"$skip": skip}, {"$limit": limit}],
                                "total": [{"$count": "count"}]}})

    agg = list(documents.aggregate(pipeline))
    if not agg:
        return jsonify({"total": 0, "count": 0, "items": []}), 200

    facet = agg[0]
    total = (facet.get("total") or [])
    total_count = total[0]["count"] if total else 0
    items = [json_oid(d) for d in (facet.get("items") or [])]
    return jsonify({"total": total_count, "count": len(items), "items": items}), 200


